function isValidPosition(x, y) {
	return x >= 1 && x <= 11 && y >= 1 && y <= 11;
}

for (var direction in core.utils.scan) {
	var delta = core.utils.scan[direction];
	var nx = x + delta.x,
		ny = y + delta.y;

	if (!isValidPosition(nx, ny)) continue;

	var nnx = x + 2 * delta.x,
		nny = y + 2 * delta.y;

	if (core.getBlockId(nx, ny) === 'redWizard') {
		core.removeBlock(x, y);
		let id = core.getBlockId(nnx, nny, null, true);
		if (!isValidPosition(nnx, nny)) continue;
		if (id === "fire" || id === null) {
			core.removeBlock(nx, ny);
			core.setBlock('redWizard', nnx, nny);
			if (id === "fire") {
				if (isValidPosition(nnx + delta.x, nny + delta.y) && core.getBlock(nnx + delta.x, nny + delta.y, null, true) === null) core.setBlock('fire', nnx + delta.x, nny + delta.y);
				core.setBlock('fire', nx, ny);
			}

		}
	}
}

