fly.canUseItemEffect:
(function () {
	if (!core.status.maps[core.status.floorId].canFlyFrom) {
		core.drawTip(core.material.items['fly'].name + "似乎失效了", 'fly');
		return false;
	}
	if (core.nearStair() || !core.flags.flyNearStair) {
		return true;
	} else {
		if (!core.getFlag('额外功能开关') && core.flags.flyNearStair) {
			core.drawTip("只有在楼梯边才能使用" + core.material.items['fly'].name, 'fly');
			return false;
		}
		// ===== 额外功能开启 =====
		if (core.getFlag('额外功能开关')) {
			if (!core.maps._canMoveDirectly_checkGlobal()) {
				core.drawTip("当前不能瞬间移动");
				return false;
			}
			var blocks = core.status.maps[core.status.floorId].blocks;
			if (!blocks) return false;

			// 四方向偏移
			var dirs = [
				{ x: 1, y: 0 },
				{ x: -1, y: 0 },
				{ x: 0, y: 1 },
				{ x: 0, y: -1 }
			];

			var fp = ["portal", "upFloor", "downFloor"]

			for (var i = 0; i < blocks.length; i++) {
				var block = blocks[i];
				if (!block || !block.event) continue;

				var id = block.event.id;
				if (!fp.includes(id)) continue;

				var sx = block.x,
					sy = block.y;

				for (var direction in core.utils.scan) {
					var delta = core.utils.scan[direction];
					var tx = sx + delta.x,
						ty = sy + delta.y;

					if (core.canMoveDirectly(tx, ty) >= 0) {
						return true;
					}
				}
			}
			core.drawTip("无法到达任何一个楼梯边");
			return false;
		}

	}
	return false;
})();

