bomb.useItemEffect:
(function () {
	var bombList = [],
		todo = [],
		money = 0;
	var heroX = core.getHeroLoc('x'),
		heroY = core.getHeroLoc('y');

	// 用于记录需要移除的坐标，格式为 "x,y": true
	var targets = {};

	// 检查可炸目标
	var canBomb = function (x, y) {
		var block = core.getBlock(x, y);
		if (block && !block.disable && block.event.trigger === 'battle' && block.event.cls.indexOf('enemy') === 0) {
			var enemy = core.material.enemys[block.event.id];
			var hp = core.getEnemyValue(enemy, 'hp', x, y);
			return hp < 500;
		}
	};

	// 预处理炸弹逻辑（只计算数据和标记，不移除）
	var prepareBomb = function (x, y) {
		if (!canBomb(x, y)) return;
		bombList.push([x, y]);

		// 标记该坐标需要移除
		targets[x + "," + y] = true;

		var enemy = core.material.enemys[core.getBlockId(x, y)];
		money += core.getEnemyInfo(enemy, null, x, y).money || 0;
		core.push(todo, core.floors[core.status.floorId].afterBattle[x + "," + y]);
		core.push(todo, enemy.afterBattle);
	};

	// 扫描四周
	var scan = core.utils.scan;
	for (var direction in scan) {
		var delta = scan[direction];
		prepareBomb(heroX + delta.x, heroY + delta.y);
	}

	// 如果有目标被炸到，执行批量移除
	if (bombList.length > 0) {
		var indexes = [];
		// 遍历当前地图所有图块，寻找匹配的坐标
		// 这样只需要遍历一次 blocks 数组，而不是每个方向遍历一次
		for (var index in core.status.thisMap.blocks) {
			var block = core.status.thisMap.blocks[index];
			if (targets[block.x + "," + block.y]) {
				indexes.push(index);
			}
		}
		// 批量移除
		core.removeBlockByIndexes(indexes);
		core.redrawMap();
	}

	core.playSound('炸弹');
	core.drawTip(core.material.items[itemId].name + '使用成功，你获得了 ' + money + ' 金币');
	core.status.hero.money += money;

	// 触发战后事件
	if (todo.length > 0) core.insertAction(todo);
})();

