function(){
// 四方向相对于格子中心的原始“图心”偏移（单位：像素）
const groupOffsets = {
	up: { x: 0, y: -8 },
	right: { x: 8, y: 0 },
	down: { x: 0, y: 8 },
	left: { x: -8, y: 0 }
};

// 可复用的旋转函数（旋转向量 (vx,vy) by angle radians）
function rotateVec(vx, vy, angle) {
	var c = Math.cos(angle),
		s = Math.sin(angle);
	return { x: vx * c - vy * s, y: vx * s + vy * c };
}

/**
 * 在格子中心作为枢轴，让四张图一起顺时针旋转 180°（默认）。
 * x,y 为格子坐标（格子左上角为 x*32,y*32）
 * duration 毫秒，rotateSelf: 是否让每张图自身也跟着旋转（true = 图也自转）
 */
function showGroupPivotRotatingDamage(x, y, duration = 500) {
	var image = core.material.images.images['85.png'];
	if (!image) return;
	var start = Date.now();
	var dirs = ['up', 'right', 'down', 'left'];
	var tileCX = x * 32 + 16; // 格子中心 x (像素)
	var tileCY = y * 32 + 16; // 格子中心 y (像素)
	var w = 16,
		h = 16; // 绘制大小（图大小或你想要的大小）

	// 如果你想让初始状态是四方向都存在（如用户所说），就直接开始绘制
	function frame() {
		var now = Date.now();
		var p = (now - start) / duration;
		if (p > 1) p = 1;

		// 顺时针旋转角度从 0 到 PI (180°)
		var baseAngle = p * Math.PI;

		// 清空 event2 层（只清该层以免破坏其他层）
		core.clearMap('event2');

		// 对每个方向计算旋转后的位置并绘制
		dirs.forEach(function (dir) {
			var off = groupOffsets[dir];
			// 先把原向量绕格子中心旋转 baseAngle（顺时针 -> 用正角）
			var r = rotateVec(off.x, off.y, baseAngle);

			// 求出图像的目标左上角，使图心放在 (tileCX + r.x, tileCY + r.y)
			var destCenterX = tileCX + r.x;
			var destCenterY = tileCY + r.y;
			var x1 = Math.round(destCenterX - w / 2);
			var y1 = Math.round(destCenterY - h / 2);

			// 如果要让图自身也旋转（和组一起转），设 angleSelf；否则 angleSelf = 0
			var angleSelf = 0;
			// 让图的朝向也随组旋转：原本朝向角（up 为 0，其它按 baseDirectionAngles） + baseAngle
			var baseDirAngle = (dir === 'up' ? 0 : dir === 'right' ? Math.PI / 2 : dir === 'down' ? Math.PI : Math.PI * 3 / 2);
			angleSelf = baseDirAngle + baseAngle;

			// 使用你已有的 core.drawImage 的参数签名：
			// core.drawImage(name, image, sx, sy, sw, sh, dx, dy, dw, dh, angle)
			// 这里假设素材整张就是 16x16（若不是请调整 sx,sy,sw,sh）
			core.drawImage(
				'event2',
				image,
				0, 0, w, h,
				x1, y1, w, h,
				angleSelf // 旋转围绕每张图的自身中心（注意：我们的位移已完成“围绕格子中心”的旋转）
			);
		});

		if (p < 1) {
			requestAnimationFrame(frame);
		} else {
			// 动画结束：如果想保留最后一帧短时显示，可取消下面清除
			// core.clearMap('event2');
			core.drawMap(); // 确保其他层正确覆盖
		}
	}

	requestAnimationFrame(frame);
}
showGroupPivotRotatingDamage(core.getHeroLoc('x'), core.getHeroLoc('y'))
}
